import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole, HEAD_OFFICE_ID } from '../types';
import { Package, Truck, ArrowRight, RefreshCw } from 'lucide-react';

const Inventory = () => {
  const { products, stocks, hubs, currentUser, transferStock } = useERP();
  const [transferModalOpen, setTransferModalOpen] = useState(false);

  // Transfer State
  const [selectedProduct, setSelectedProduct] = useState('');
  const [targetHub, setTargetHub] = useState('');
  const [transferQty, setTransferQty] = useState(0);

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const getStock = (productId: string, hubId: string) => {
    return stocks.find(s => s.productId === productId && s.hubId === hubId)?.quantity || 0;
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProduct || !targetHub || transferQty <= 0) return;

    try {
        transferStock(selectedProduct, HEAD_OFFICE_ID, targetHub, transferQty);
        setTransferModalOpen(false);
        setTransferQty(0);
        alert("Stock transferred successfully!");
    } catch (err) {
        alert("Transfer failed: Insufficient stock at Head Office.");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Inventory Management</h1>
          <p className="text-slate-500">Real-time stock tracking across all hubs.</p>
        </div>
        {isSuperAdmin && (
          <button 
            onClick={() => setTransferModalOpen(true)}
            className="flex items-center px-4 py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-sm transition-colors"
          >
            <Truck className="mr-2 h-4 w-4" />
            Distribute Stock
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {products.map((product) => (
          <div key={product.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-white rounded-md border border-slate-200">
                  <Package className="text-sun-500 h-6 w-6" />
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">{product.name}</h3>
                  <p className="text-xs text-slate-500">SKU: {product.sku}</p>
                </div>
              </div>
              <div className="text-right">
                <div className="text-sm text-slate-500">Unit Price</div>
                <div className="font-bold text-slate-800">${product.sellingPrice}</div>
              </div>
            </div>

            <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {/* Head Office Stock (Only visible to SA) */}
              {isSuperAdmin && (
                <div className="p-3 bg-indigo-50 rounded-lg border border-indigo-100">
                    <div className="text-xs font-bold text-indigo-800 uppercase mb-1">Head Office (Unified)</div>
                    <div className="text-2xl font-bold text-indigo-900">
                        {getStock(product.id, HEAD_OFFICE_ID).toLocaleString()}
                        <span className="text-xs font-normal text-indigo-600 ml-1">units</span>
                    </div>
                </div>
              )}

              {/* Hub Stocks */}
              {hubs.map(hub => {
                  const qty = getStock(product.id, hub.id);
                  const isMyHub = currentUser?.hubId === hub.id;

                  // Filter visibility: SA sees all, HubAdmin sees own
                  if (!isSuperAdmin && !isMyHub) return null;

                  return (
                    <div key={hub.id} className="p-3 bg-white rounded-lg border border-slate-200">
                         <div className="flex justify-between items-start mb-1">
                            <div className="text-xs font-bold text-slate-600 uppercase">{hub.name}</div>
                            {isMyHub && <div className="px-2 py-0.5 bg-green-100 text-green-700 text-[10px] rounded-full">My Hub</div>}
                         </div>
                        <div className={`text-2xl font-bold ${qty < 100 ? 'text-red-600' : 'text-slate-800'}`}>
                            {qty.toLocaleString()}
                            <span className="text-xs font-normal text-slate-500 ml-1">units</span>
                        </div>
                    </div>
                  );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Transfer Modal */}
      {transferModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl max-w-md w-full p-6 shadow-2xl animate-fade-in">
            <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
                <RefreshCw className="mr-2 text-sun-600" />
                Distribute Stock
            </h2>
            <form onSubmit={handleTransfer} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Product</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={selectedProduct}
                        onChange={e => setSelectedProduct(e.target.value)}
                        required
                    >
                        <option value="">Select Product</option>
                        {products.map(p => (
                            <option key={p.id} value={p.id}>{p.name} (HQ: {getStock(p.id, HEAD_OFFICE_ID)})</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Destination Hub</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={targetHub}
                        onChange={e => setTargetHub(e.target.value)}
                        required
                    >
                        <option value="">Select Hub</option>
                        {hubs.map(h => (
                            <option key={h.id} value={h.id}>{h.name}</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Quantity</label>
                    <input 
                        type="number" 
                        min="1"
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={transferQty}
                        onChange={e => setTransferQty(parseInt(e.target.value))}
                        required
                    />
                </div>

                <div className="flex space-x-3 mt-6">
                    <button 
                        type="button"
                        onClick={() => setTransferModalOpen(false)}
                        className="flex-1 py-2 px-4 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit"
                        className="flex-1 py-2 px-4 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md"
                    >
                        Transfer
                    </button>
                </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { InvoiceTemplate } from '../services/invoiceGenerator';
import { UserRole, Invoice, InvoiceItem } from '../types';
import { Plus, Trash2, Printer, Share2, Search, FilePlus } from 'lucide-react';

const Invoices = () => {
  const { 
    currentUser, products, customers, invoices, 
    createInvoice, addCustomer, stocks 
  } = useERP();

  const [view, setView] = useState<'LIST' | 'CREATE'>('LIST');
  const [searchTerm, setSearchTerm] = useState('');

  // Creation State
  const [newCustType, setNewCustType] = useState<'EXISTING' | 'NEW'>('EXISTING');
  const [selectedCustId, setSelectedCustId] = useState('');
  const [guestDetails, setGuestDetails] = useState({ name: '', phone: '', address: '' });
  const [cart, setCart] = useState<InvoiceItem[]>([]);

  // Filter invoices for current user's hub (unless SA)
  const myHubId = currentUser?.hubId;
  const filteredInvoices = invoices.filter(inv => {
    const matchesSearch = inv.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || inv.id.includes(searchTerm);
    if (currentUser?.role === UserRole.SUPER_ADMIN) return matchesSearch;
    return inv.hubId === myHubId && matchesSearch;
  });

  const getStock = (productId: string) => {
    const hub = currentUser?.hubId;
    if (!hub) return 0;
    return stocks.find(s => s.productId === productId && s.hubId === hub)?.quantity || 0;
  };

  const addToCart = (productId: string) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    const currentQtyInCart = cart.find(c => c.productId === productId)?.quantity || 0;
    const available = getStock(productId);

    if (currentQtyInCart + 1 > available) {
        alert("Insufficient stock in your hub!");
        return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === productId);
      if (existing) {
        return prev.map(item => item.productId === productId ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId, quantity: 1, priceAtSale: product.sellingPrice }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.productId !== productId));
  };

  const handleCreateInvoice = () => {
    if (cart.length === 0) return;

    let custId = selectedCustId;
    let custName = '';

    if (newCustType === 'NEW') {
        custId = `c-${Date.now()}`;
        custName = guestDetails.name;
        addCustomer({
            id: custId,
            name: guestDetails.name,
            phone: guestDetails.phone,
            address: guestDetails.address,
            type: 'GUEST' // Or REGISTERED if you want full reg
        });
    } else {
        const c = customers.find(c => c.id === selectedCustId);
        if (!c) return alert("Select a customer");
        custName = c.name;
    }

    const total = cart.reduce((acc, item) => acc + (item.quantity * item.priceAtSale), 0);

    const newInvoice: Invoice = {
        id: `INV-${Date.now().toString().slice(-6)}`,
        date: new Date().toISOString(),
        customerId: custId,
        customerName: custName,
        hubId: currentUser?.hubId || 'HEAD_OFFICE',
        items: cart,
        totalAmount: total,
        status: 'PAID', // Assuming instant cash payment for this ERP
        createdBy: currentUser?.id || 'unknown'
    };

    createInvoice(newInvoice);
    setView('LIST');
    setCart([]);
    setGuestDetails({ name: '', phone: '', address: '' });
  };

  const handlePrint = (invId: string) => {
      // Logic to trigger browser print
      const printContent = document.getElementById(`invoice-${invId}`);
      if (printContent) {
          window.print();
      } else {
          alert("Rendering invoice for print... please wait a split second and try again (in real app this opens a PDF url)");
      }
  };

  const handleWhatsApp = (inv: Invoice) => {
      const customer = customers.find(c => c.id === inv.customerId);
      const phone = customer?.phone || '0000000000';
      const message = `Hello ${inv.customerName}, here is your invoice #${inv.id} from Sun Cola for $${inv.totalAmount}. Thank you!`;
      const url = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
      window.open(url, '_blank');
  };

  return (
    <div className="space-y-6">
       {/* Invoice Template Rendering Area (Hidden until print) */}
       <div>
         {invoices.map(inv => (
             <InvoiceTemplate 
                key={inv.id} 
                invoice={inv} 
                products={products} 
                customer={customers.find(c => c.id === inv.customerId)} 
             />
         ))}
       </div>

      <div className="flex justify-between items-center no-print">
        <h1 className="text-2xl font-bold text-slate-800">{view === 'LIST' ? 'Invoices' : 'New Invoice'}</h1>
        {view === 'LIST' && currentUser?.role !== UserRole.SUPER_ADMIN && (
          <button 
            onClick={() => setView('CREATE')}
            className="flex items-center px-4 py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md"
          >
            <Plus className="mr-2 h-4 w-4" />
            Create Invoice
          </button>
        )}
        {view === 'CREATE' && (
          <button onClick={() => setView('LIST')} className="text-slate-500 hover:text-slate-800">Cancel</button>
        )}
      </div>

      {view === 'LIST' ? (
        <div className="space-y-4 no-print">
            <div className="relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-slate-400" />
                <input 
                    type="text" 
                    placeholder="Search invoices..." 
                    className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sun-500 outline-none"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-slate-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Invoice ID</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Customer</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Date</th>
                                <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">Amount</th>
                                <th className="px-6 py-3 text-center text-xs font-bold text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-slate-200">
                            {filteredInvoices.map(inv => (
                                <tr key={inv.id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">#{inv.id}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{inv.customerName}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{new Date(inv.date).toLocaleDateString()}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-right font-bold text-slate-700">${inv.totalAmount.toFixed(2)}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-center text-sm font-medium space-x-2">
                                        <button onClick={() => handlePrint(inv.id)} className="text-slate-600 hover:text-sun-600">
                                            <Printer size={18} />
                                        </button>
                                        {(currentUser?.role === UserRole.SUPER_ADMIN) && (
                                            <button onClick={() => handleWhatsApp(inv)} className="text-green-600 hover:text-green-800">
                                                <Share2 size={18} />
                                            </button>
                                        )}
                                    </td>
                                </tr>
                            ))}
                            {filteredInvoices.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-slate-400">No invoices found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
            {/* Left: Product Selection */}
            <div className="lg:col-span-2 space-y-6">
                <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="font-bold text-slate-800 mb-4">Select Products</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                        {products.map(p => {
                            const stock = getStock(p.id);
                            return (
                                <button 
                                    key={p.id}
                                    onClick={() => addToCart(p.id)}
                                    disabled={stock === 0}
                                    className={`p-4 rounded-lg border text-left transition-all ${
                                        stock > 0 
                                        ? 'border-slate-200 hover:border-sun-500 hover:bg-sun-50' 
                                        : 'border-slate-100 bg-slate-50 opacity-50 cursor-not-allowed'
                                    }`}
                                >
                                    <div className="font-bold text-slate-800">{p.name}</div>
                                    <div className="text-sm text-slate-500">${p.sellingPrice}</div>
                                    <div className={`text-xs mt-2 ${stock < 10 ? 'text-red-500' : 'text-green-600'}`}>
                                        Stock: {stock}
                                    </div>
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                     <h3 className="font-bold text-slate-800 mb-4">Customer Details</h3>
                     <div className="flex space-x-4 mb-4">
                         <button 
                            className={`flex-1 py-2 rounded-lg text-sm font-medium ${newCustType === 'EXISTING' ? 'bg-sun-100 text-sun-800' : 'bg-slate-100 text-slate-600'}`}
                            onClick={() => setNewCustType('EXISTING')}
                         >
                             Existing Customer
                         </button>
                         <button 
                            className={`flex-1 py-2 rounded-lg text-sm font-medium ${newCustType === 'NEW' ? 'bg-sun-100 text-sun-800' : 'bg-slate-100 text-slate-600'}`}
                            onClick={() => setNewCustType('NEW')}
                         >
                             New / Guest
                         </button>
                     </div>

                     {newCustType === 'EXISTING' ? (
                         <select 
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none"
                            value={selectedCustId}
                            onChange={(e) => setSelectedCustId(e.target.value)}
                         >
                             <option value="">Select Customer</option>
                             {customers.map(c => (
                                 <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                             ))}
