                                value={guestDetails.phone} onChange={e => setGuestDetails({...guestDetails, phone: e.target.value})}
                             />
                             <input 
                                type="text" placeholder="Address (Optional)" className="w-full p-2 border border-slate-300 rounded-lg"
                                value={guestDetails.address} onChange={e => setGuestDetails({...guestDetails, address: e.target.value})}
                             />
                         </div>
                     )}
                </div>
            </div>

            {/* Right: Cart Summary */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
                <h3 className="font-bold text-lg text-slate-800 mb-4">Current Invoice</h3>
                <div className="space-y-4 mb-6">
                    {cart.map(item => {
                        const p = products.find(prod => prod.id === item.productId);
                        return (
                            <div key={item.productId} className="flex justify-between items-center text-sm">
                                <div>
                                    <div className="font-medium text-slate-800">{p?.name}</div>
                                    <div className="text-slate-500">{item.quantity} x ${item.priceAtSale}</div>
                                </div>
                                <div className="flex items-center space-x-3">
                                    <span className="font-bold text-slate-800">${(item.quantity * item.priceAtSale).toFixed(2)}</span>
                                    <button onClick={() => removeFromCart(item.productId)} className="text-red-400 hover:text-red-600">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                    {cart.length === 0 && (
                        <div className="text-center text-slate-400 py-4">Cart is empty</div>
                    )}
                </div>

                <div className="border-t border-slate-200 pt-4 mb-6">
                    <div className="flex justify-between items-center text-xl font-bold text-slate-800">
                        <span>Total</span>
                        <span>${cart.reduce((acc, item) => acc + (item.quantity * item.priceAtSale), 0).toFixed(2)}</span>
