import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { DollarSign, Wallet, FileText, PieChart as PieChartIcon } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

const Finance = () => {
  const { currentUser, transactions, addSalarySlip, salarySlips } = useERP();
  const [activeTab, setActiveTab] = useState<'PNL' | 'SALARY'>('PNL');

  // Salary Form
  const [empName, setEmpName] = useState('');
  const [salary, setSalary] = useState(0);

  if (currentUser?.role !== UserRole.SUPER_ADMIN) {
      return <div className="text-red-500">Access Denied</div>;
  }

  // Financial Calcs
  const totalIncome = transactions.filter(t => t.type === 'INCOME').reduce((acc, c) => acc + c.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'EXPENSE').reduce((acc, c) => acc + c.amount, 0);
  const netProfit = totalIncome - totalExpense;

  const dataPnl = [
      { name: 'Income', value: totalIncome, color: '#10b981' },
      { name: 'Expense', value: totalExpense, color: '#ef4444' }
  ];

  const handleCreateSalary = (e: React.FormEvent) => {
      e.preventDefault();
      if (!empName || salary <= 0) return;

      addSalarySlip({
          id: Date.now().toString(),
          employeeName: empName,
          role: 'Staff',
          month: new Date().toLocaleString('default', { month: 'long' }),
          basicSalary: salary,
          bonus: 0,
          deductions: 0,
          netSalary: salary,
          dateGenerated: new Date().toISOString()
      });
      setEmpName('');
      setSalary(0);
  };

  return (
    <div className="space-y-6">
      <div className="flex space-x-4 border-b border-slate-200 pb-4">
        <button 
            onClick={() => setActiveTab('PNL')}
            className={`flex items-center px-4 py-2 rounded-lg font-medium transition-colors ${activeTab === 'PNL' ? 'bg-sun-100 text-sun-700' : 'text-slate-500 hover:bg-slate-50'}`}
        >
            <PieChartIcon className="mr-2 h-5 w-5" />
            Profit & Loss
        </button>
        <button 
            onClick={() => setActiveTab('SALARY')}
            className={`flex items-center px-4 py-2 rounded-lg font-medium transition-colors ${activeTab === 'SALARY' ? 'bg-sun-100 text-sun-700' : 'text-slate-500 hover:bg-slate-50'}`}
        >
            <Wallet className="mr-2 h-5 w-5" />
            Cash & Payroll
        </button>
      </div>

      {activeTab === 'PNL' ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h2 className="text-lg font-bold text-slate-800 mb-6">Financial Overview</h2>
                <div className="space-y-4">
                    <div className="flex justify-between items-center p-4 bg-green-50 rounded-lg border border-green-100">
                        <span className="text-green-800 font-medium">Total Income</span>
                        <span className="text-xl font-bold text-green-700">+${totalIncome.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center p-4 bg-red-50 rounded-lg border border-red-100">
                        <span className="text-red-800 font-medium">Total Expenses</span>
                        <span className="text-xl font-bold text-red-700">-${totalExpense.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center p-4 bg-slate-50 rounded-lg border border-slate-200 mt-4">
                        <span className="text-slate-800 font-bold">Net Profit</span>
                        <span className={`text-2xl font-bold ${netProfit >= 0 ? 'text-blue-600' : 'text-red-600'}`}>
                            ${netProfit.toLocaleString()}
                        </span>
                    </div>
                </div>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col items-center justify-center">
                 <h2 className="text-lg font-bold text-slate-800 mb-4">Ratio Analysis</h2>
                 <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie 
                                data={dataPnl} 
                                innerRadius={60} 
                                outerRadius={80} 
                                paddingAngle={5} 
                                dataKey="value"
                            >
                                {dataPnl.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
                            </Pie>
                            <Tooltip />
                        </PieChart>
                    </ResponsiveContainer>
                 </div>
                 <div className="flex space-x-6 mt-4">
                     {dataPnl.map((item, idx) => (
                         <div key={idx} className="flex items-center text-sm">
                             <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: item.color }}></div>
                             <span className="text-slate-600">{item.name}</span>
                         </div>
                     ))}
                 </div>
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
                <h2 className="text-lg font-bold text-slate-800 mb-4">Generate Salary Slip</h2>
                <form onSubmit={handleCreateSalary} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-600 mb-1">Employee Name</label>
                        <input 
                            type="text" required
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500"
                            value={empName} onChange={e => setEmpName(e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-600 mb-1">Net Pay Amount ($)</label>
                        <input 
                            type="number" required min="1"
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500"
                            value={salary} onChange={e => setSalary(parseFloat(e.target.value))}
                        />
                    </div>
                    <button className="w-full py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md">
                        Process Payment
                    </button>
                </form>
            </div>

            <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 border-b border-slate-200 bg-slate-50">
                    <h2 className="font-bold text-slate-700">Recent Salary Disbursements</h2>
                </div>
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-white">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Employee</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Month</th>
                                <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">Net Pay</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Date</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200">
                            {salarySlips.map(slip => (
                                <tr key={slip.id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 text-sm font-medium text-slate-900">{slip.employeeName}</td>
                                    <td className="px-6 py-4 text-sm text-slate-500">{slip.month}</td>
                                    <td className="px-6 py-4 text-sm text-right font-bold text-slate-700">${slip.netSalary}</td>
                                    <td className="px-6 py-4 text-sm text-slate-500">{new Date(slip.dateGenerated).toLocaleDateString()}</td>
                                </tr>
                            ))}
                            {salarySlips.length === 0 && (
                                <tr><td colSpan={4} className="text-center py-6 text-slate-400">No records found</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Finance;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole, INITIAL_HUBS, User } from '../types';
import { Users as UserIcon, Shield, MapPin, Plus } from 'lucide-react';

const UsersPage = () => {
  const { users, addUser, hubs, currentUser } = useERP();
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [newUser, setNewUser] = useState<Partial<User>>({
      username: '', fullName: '', role: UserRole.STAFF, hubId: ''
  });

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newUser.username || !newUser.fullName) return;

      addUser({
          id: `u-${Date.now()}`,
          username: newUser.username,
          fullName: newUser.fullName,
          role: newUser.role as UserRole,
          hubId: newUser.role === UserRole.SUPER_ADMIN ? undefined : (newUser.hubId || currentUser?.hubId),
          permissions: [],
          phone: ''
      });
      setShowForm(false);
      setNewUser({ username: '', fullName: '', role: UserRole.STAFF, hubId: '' });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">User Management</h1>
           <p className="text-slate-500">Manage system access and roles.</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-colors"
        >
          <Plus className="mr-2 h-4 w-4" />
          Add User
        </button>
      </div>

      {showForm && (
          <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200 animate-fade-in">
              <h3 className="text-lg font-bold mb-4">Create New User</h3>
              <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input 
                    placeholder="Username" required
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}
                  />
                  <input 
                    placeholder="Full Name" required
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.fullName} onChange={e => setNewUser({...newUser, fullName: e.target.value})}
                  />
                  <select 
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.role} 
                    onChange={e => setNewUser({...newUser, role: e.target.value as UserRole})}
                  >
                      <option value={UserRole.STAFF}>Staff</option>
                      {isSuperAdmin && <option value={UserRole.HUB_ADMIN}>Hub Admin</option>}
                      {isSuperAdmin && <option value={UserRole.SUPER_ADMIN}>Super Admin</option>}
                  </select>

                  {/* Hub Selection only if SA creating Hub Admin or Staff */}
                  {isSuperAdmin && newUser.role !== UserRole.SUPER_ADMIN && (
                      <select 
                        className="p-2 border border-slate-300 rounded-lg"
                        value={newUser.hubId} 
                        onChange={e => setNewUser({...newUser, hubId: e.target.value})}
                        required
                      >
                          <option value="">Select Hub</option>
                          {hubs.map(h => <option key={h.id} value={h.id}>{h.name}</option>)}
                      </select>
                  )}

                  <div className="md:col-span-2 flex justify-end mt-2">
                      <button type="submit" className="px-6 py-2 bg-sun-600 text-white rounded-lg font-medium">Create User</button>
                  </div>
              </form>
          </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(user => (
              <div key={user.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col relative overflow-hidden group">
                  <div className={`absolute top-0 left-0 w-1 h-full ${
                      user.role === UserRole.SUPER_ADMIN ? 'bg-purple-500' :
                      user.role === UserRole.HUB_ADMIN ? 'bg-blue-500' : 'bg-green-500'
                  }`} />

                  <div className="flex items-start justify-between mb-4 pl-3">
                      <div className="flex items-center space-x-3">
                          <div className="bg-slate-100 p-2 rounded-full">
                              <UserIcon size={20} className="text-slate-600" />
                          </div>
                          <div>
                              <h3 className="font-bold text-slate-800">{user.fullName}</h3>
                              <p className="text-sm text-slate-500">@{user.username}</p>
                          </div>
                      </div>
                      <span className="text-xs font-bold uppercase px-2 py-1 bg-slate-100 text-slate-600 rounded">
                          {user.role.replace('_', ' ')}
                      </span>
                  </div>

                  <div className="pl-3 mt-auto space-y-2">
                      <div className="flex items-center text-sm text-slate-600">
                          <Shield size={14} className="mr-2 text-slate-400" />
                          <span>{user.role === UserRole.SUPER_ADMIN ? 'Full Access' : 'Restricted Access'}</span>
                      </div>
                      {user.hubId && (
                          <div className="flex items-center text-sm text-slate-600">
                              <MapPin size={14} className="mr-2 text-slate-400" />
                              <span>{hubs.find(h => h.id === user.hubId)?.name || 'Unknown Hub'}</span>
                          </div>
                      )}
                  </div>
              </div>
          ))}
      </div>
    </div>
  );
};

export default UsersPage;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { GoogleGenAI } from "@google/genai";
import { Sparkles, Loader2, Send } from 'lucide-react';

const AIAnalysis = () => {
  const { currentUser, transactions, stocks, products } = useERP();
  const [prompt, setPrompt] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);

  // We mock the API call here as we can't reliably inject a real key in a demo
  // In a real scenario, this would use process.env.API_KEY
  const handleAskAI = async () => {
    if (!prompt) return;
    setLoading(true);

    try {
        // Construct context from current ERP state
        const salesSummary = transactions
            .filter(t => t.type === 'INCOME')
            .slice(-20)
            .map(t => `${t.date.split('T')[0]}: $${t.amount} (${t.category})`)
            .join('\n');

        const stockSummary = stocks
            .map(s => {
                const p = products.find(prod => prod.id === s.productId);
                return `${p?.name}: ${s.quantity}`;
            })
            .join(', ');

        const systemInstruction = `
            You are an expert ERP analyst for Sun Cola Pvt. 
            Analyze the following data:
            Recent Sales: ${salesSummary}
            Current Stocks: ${stockSummary}

            User Question: ${prompt}

            Provide a concise, strategic insight or answer.
        `;

        // Check if API key exists (simulated environment check)
        if (process.env.API_KEY) {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const result = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: systemInstruction,
            });
            setResponse(result.text || "No insights generated.");
        } else {
            // Fallback for demo without key
            await new Promise(r => setTimeout(r, 1500));
            setResponse(`(Demo Mode - API Key missing) Based on your data, Sun Cola sales are trending upwards. Recommend restocking "Sun Cola 1.5L" in North Hub as quantities are below 500 units. Consider a promotion for Lemon flavor to boost sales velocity.`);
        }
    } catch (error) {
        setResponse("Error connecting to AI service. Please try again.");
    } finally {
        setLoading(false);
    }
  };

  if (currentUser?.role !== UserRole.SUPER_ADMIN) return null;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
        <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-xl p-8 text-white shadow-lg">
            <div className="flex items-center mb-4">
                <Sparkles className="h-8 w-8 mr-3 text-yellow-300" />
                <h1 className="text-3xl font-bold">Smart Insights AI</h1>
            </div>
            <p className="text-indigo-100 text-lg">
                Ask deeper questions about your sales trends, stock prediction, or financial health.
            </p>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
            <div className="flex gap-4">
                <input 
                    type="text" 
                    className="flex-1 p-4 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 text-lg"
                    placeholder="e.g., 'Analyze sales trends for this week' or 'Which product needs restocking?'"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleAskAI()}
                />
                <button 
                    onClick={handleAskAI}
                    disabled={loading || !prompt}
                    className="px-8 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 font-bold flex items-center"
                >
                    {loading ? <Loader2 className="animate-spin h-6 w-6" /> : <Send className="h-6 w-6" />}
                </button>
            </div>

            {response && (
                <div className="mt-8 p-6 bg-slate-50 rounded-lg border border-slate-200 animate-fade-in">
                    <h3 className="text-indigo-900 font-bold mb-2 flex items-center">
                        <Sparkles className="h-4 w-4 mr-2" />
                        AI Analysis Result
                    </h3>
                    <p className="text-slate-700 leading-relaxed whitespace-pre-wrap">{response}</p>
                </div>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm text-slate-500">
            <div className="bg-white p-4 rounded-lg border border-slate-200 cursor-pointer hover:border-indigo-300 transition-colors"
                 onClick={() => setPrompt("What is our best selling product?")}>
                "What is our best selling product?"
            </div>
            <div className="bg-white p-4 rounded-lg border border-slate-200 cursor-pointer hover:border-indigo-300 transition-colors"
                 onClick={() => setPrompt("Draft a restocking plan for North Hub")}>
                "Draft a restocking plan for North Hub"
            </div>
            <div className="bg-white p-4 rounded-lg border border-slate-200 cursor-pointer hover:border-indigo-300 transition-colors"
                 onClick={() => setPrompt("Analyze profit margins for current month")}>
                "Analyze profit margins"
            </div>
        </div>
    </div>
  );
};

export default AIAnalysis;

import React, { useState } from 'react';
import { ERPProvider, useERP } from './contexts/ERPContext';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import Invoices from './pages/Invoices';
import Finance from './pages/Finance';
import UsersPage from './pages/Users';
import AIAnalysis from './pages/AIAnalysis';
import { Menu } from 'lucide-react';

const LoginPage = () => {
  const { login } = useERP();
  const [username, setUsername] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!login(username)) {
      setError('Invalid username (Try: admin, hub1admin, staff1)');
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-sun-500 to-orange-600 flex items-center justify-center p-4">
      <div className="bg-white p-8 rounded-2xl shadow-2xl max-w-md w-full">
        <div className="text-center mb-8">
            <h1 className="text-4xl font-bold text-sun-600 mb-2">Sun Cola ERP</h1>
            <p className="text-gray-500">Enterprise Resource Planning</p>
        </div>
        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Username</label>
            <input 
              type="text" 
              className="w-full p-3 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500"
              placeholder="admin"
              value={username}
              onChange={e => setUsername(e.target.value)}
            />
          </div>
          {error && <p className="text-red-500 text-sm text-center">{error}</p>}
          <button className="w-full bg-slate-900 text-white py-3 rounded-lg font-bold hover:bg-slate-800 transition-all">
            Login to System
          </button>
        </form>
        <div className="mt-6 text-center text-xs text-gray-400">
            <p>Demo Creds: admin, hub1admin, staff1</p>
        </div>
      </div>
    </div>
  );
};

const MainLayout = () => {
  const { currentUser } = useERP();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState('dashboard');

  if (!currentUser) return <LoginPage />;

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'inventory': return <Inventory />;
      case 'invoices': return <Invoices />;
      case 'finance': return <Finance />;
      case 'users': return <UsersPage />;
      case 'ai-analysis': return <AIAnalysis />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        isOpen={sidebarOpen} 
        setIsOpen={setSidebarOpen} 
        currentPage={currentPage}
        setPage={setCurrentPage}
      />

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {/* Mobile Header */}
        <header className="bg-white border-b border-slate-200 p-4 md:hidden flex justify-between items-center z-10">
          <div className="font-bold text-sun-600">Sun Cola ERP</div>
          <button onClick={() => setSidebarOpen(true)} className="text-slate-600">
            <Menu size={24} />
          </button>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderPage()}
        </main>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <ERPProvider>
      <MainLayout />
    </ERPProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { HEAD_OFFICE_ID } from '../constants';
import { Package, Truck, ArrowRight, RefreshCw } from 'lucide-react';

const Inventory = () => {
  const { products, stocks, hubs, currentUser, transferStock } = useERP();
  const [transferModalOpen, setTransferModalOpen] = useState(false);

  // Transfer State
  const [selectedProduct, setSelectedProduct] = useState('');
  const [targetHub, setTargetHub] = useState('');
  const [transferQty, setTransferQty] = useState(0);

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const getStock = (productId: string, hubId: string) => {
    return stocks.find(s => s.productId === productId && s.hubId === hubId)?.quantity || 0;
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProduct || !targetHub || transferQty <= 0) return;

    try {
        transferStock(selectedProduct, HEAD_OFFICE_ID, targetHub, transferQty);
        setTransferModalOpen(false);
        setTransferQty(0);
        alert("Stock transferred successfully!");
    } catch (err) {
        alert("Transfer failed: Insufficient stock at Head Office.");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Inventory Management</h1>
          <p className="text-slate-500">Real-time stock tracking across all hubs.</p>
        </div>
        {isSuperAdmin && (
          <button 
            onClick={() => setTransferModalOpen(true)}
            className="flex items-center px-4 py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-sm transition-colors"
          >
            <Truck className="mr-2 h-4 w-4" />
            Distribute Stock
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {products.map((product) => (
          <div key={product.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-white rounded-md border border-slate-200">
                  <Package className="text-sun-500 h-6 w-6" />
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">{product.name}</h3>
                  <p className="text-xs text-slate-500">SKU: {product.sku}</p>
                </div>
              </div>
              <div className="text-right">
                <div className="text-sm text-slate-500">Unit Price</div>
                <div className="font-bold text-slate-800">${product.sellingPrice}</div>
              </div>
            </div>

            <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {/* Head Office Stock (Only visible to SA) */}
              {isSuperAdmin && (
                <div className="p-3 bg-indigo-50 rounded-lg border border-indigo-100">
                    <div className="text-xs font-bold text-indigo-800 uppercase mb-1">Head Office (Unified)</div>
                    <div className="text-2xl font-bold text-indigo-900">
                        {getStock(product.id, HEAD_OFFICE_ID).toLocaleString()}
                        <span className="text-xs font-normal text-indigo-600 ml-1">units</span>
                    </div>
                </div>
              )}

              {/* Hub Stocks */}
              {hubs.map(hub => {
                  const qty = getStock(product.id, hub.id);
                  const isMyHub = currentUser?.hubId === hub.id;

                  // Filter visibility: SA sees all, HubAdmin sees own
                  if (!isSuperAdmin && !isMyHub) return null;

                  return (
                    <div key={hub.id} className="p-3 bg-white rounded-lg border border-slate-200">
                         <div className="flex justify-between items-start mb-1">
                            <div className="text-xs font-bold text-slate-600 uppercase">{hub.name}</div>
                            {isMyHub && <div className="px-2 py-0.5 bg-green-100 text-green-700 text-[10px] rounded-full">My Hub</div>}
                         </div>
                        <div className={`text-2xl font-bold ${qty < 100 ? 'text-red-600' : 'text-slate-800'}`}>
                            {qty.toLocaleString()}
                            <span className="text-xs font-normal text-slate-500 ml-1">units</span>
                        </div>
                    </div>
                  );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Transfer Modal */}
      {transferModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl max-w-md w-full p-6 shadow-2xl animate-fade-in">
            <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
                <RefreshCw className="mr-2 text-sun-600" />
                Distribute Stock
            </h2>
            <form onSubmit={handleTransfer} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Product</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={selectedProduct}
                        onChange={e => setSelectedProduct(e.target.value)}
                        required
                    >
                        <option value="">Select Product</option>
                        {products.map(p => (
                            <option key={p.id} value={p.id}>{p.name} (HQ: {getStock(p.id, HEAD_OFFICE_ID)})</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Destination Hub</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={targetHub}
                        onChange={e => setTargetHub(e.target.value)}
                        required
                    >
                        <option value="">Select Hub</option>
                        {hubs.map(h => (
                            <option key={h.id} value={h.id}>{h.name}</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Quantity</label>
                    <input 
                        type="number" 
                        min="1"
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none"
                        value={transferQty}
                        onChange={e => setTransferQty(parseInt(e.target.value))}
                        required
                    />
                </div>

                <div className="flex space-x-3 mt-6">
                    <button 
                        type="button"
                        onClick={() => setTransferModalOpen(false)}
                        className="flex-1 py-2 px-4 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit"
                        className="flex-1 py-2 px-4 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md"
                    >
                        Transfer
                    </button>
                </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole, User } from '../types';
import { INITIAL_HUBS } from '../constants';
import { Users as UserIcon, Shield, MapPin, Plus } from 'lucide-react';

const UsersPage = () => {
  const { users, addUser, hubs, currentUser } = useERP();
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [newUser, setNewUser] = useState<Partial<User>>({
      username: '', fullName: '', role: UserRole.STAFF, hubId: ''
  });

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newUser.username || !newUser.fullName) return;

      addUser({
          id: `u-${Date.now()}`,
          username: newUser.username,
          fullName: newUser.fullName,
          role: newUser.role as UserRole,
          hubId: newUser.role === UserRole.SUPER_ADMIN ? undefined : (newUser.hubId || currentUser?.hubId),
          permissions: [],
          phone: ''
      });
      setShowForm(false);
      setNewUser({ username: '', fullName: '', role: UserRole.STAFF, hubId: '' });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">User Management</h1>
           <p className="text-slate-500">Manage system access and roles.</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-colors"
        >
          <Plus className="mr-2 h-4 w-4" />
          Add User
        </button>
      </div>

      {showForm && (
          <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200 animate-fade-in">
              <h3 className="text-lg font-bold mb-4">Create New User</h3>
              <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input 
                    placeholder="Username" required
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}
                  />
                  <input 
                    placeholder="Full Name" required
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.fullName} onChange={e => setNewUser({...newUser, fullName: e.target.value})}
                  />
                  <select 
                    className="p-2 border border-slate-300 rounded-lg"
                    value={newUser.role} 
                    onChange={e => setNewUser({...newUser, role: e.target.value as UserRole})}
                  >
                      <option value={UserRole.STAFF}>Staff</option>
                      {isSuperAdmin && <option value={UserRole.HUB_ADMIN}>Hub Admin</option>}
                      {isSuperAdmin && <option value={UserRole.SUPER_ADMIN}>Super Admin</option>}
                  </select>

                  {/* Hub Selection only if SA creating Hub Admin or Staff */}
                  {isSuperAdmin && newUser.role !== UserRole.SUPER_ADMIN && (
                      <select 
                        className="p-2 border border-slate-300 rounded-lg"
                        value={newUser.hubId} 
                        onChange={e => setNewUser({...newUser, hubId: e.target.value})}
                        required
                      >
                          <option value="">Select Hub</option>
                          {hubs.map(h => <option key={h.id} value={h.id}>{h.name}</option>)}
                      </select>
                  )}

                  <div className="md:col-span-2 flex justify-end mt-2">
                      <button type="submit" className="px-6 py-2 bg-sun-600 text-white rounded-lg font-medium">Create User</button>
                  </div>
              </form>
          </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(user => (
              <div key={user.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col relative overflow-hidden group">
                  <div className={`absolute top-0 left-0 w-1 h-full ${
                      user.role === UserRole.SUPER_ADMIN ? 'bg-purple-500' :
                      user.role === UserRole.HUB_ADMIN ? 'bg-blue-500' : 'bg-green-500'
                  }`} />

                  <div className="flex items-start justify-between mb-4 pl-3">
                      <div className="flex items-center space-x-3">
                          <div className="bg-slate-100 p-2 rounded-full">
                              <UserIcon size={20} className="text-slate-600" />
                          </div>
                          <div>
                              <h3 className="font-bold text-slate-800">{user.fullName}</h3>
                              <p className="text-sm text-slate-500">@{user.username}</p>
                          </div>
                      </div>
                      <span className="text-xs font-bold uppercase px-2 py-1 bg-slate-100 text-slate-600 rounded">
                          {user.role.replace('_', ' ')}
                      </span>
                  </div>

                  <div className="pl-3 mt-auto space-y-2">
                      <div className="flex items-center text-sm text-slate-600">
                          <Shield size={14} className="mr-2 text-slate-400" />
                          <span>{user.role === UserRole.SUPER_ADMIN ? 'Full Access' : 'Restricted Access'}</span>
                      </div>
                      {user.hubId && (
                          <div className="flex items-center text-sm text-slate-600">
                              <MapPin size={14} className="mr-2 text-slate-400" />
                              <span>{hubs.find(h => h.id === user.hubId)?.name || 'Unknown Hub'}</span>
                          </div>
                      )}
                  </div>
              </div>
          ))}
      </div>
    </div>
  );
};

export default UsersPage;

import React from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { 
  LayoutDashboard, Package, Users, FileText, 
  DollarSign, LogOut, Menu, X
} from 'lucide-react';

interface SidebarProps {
  isOpen: boolean;
  setIsOpen: (v: boolean) => void;
  currentPage: string;
  setPage: (p: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, setIsOpen, currentPage, setPage }) => {
  const { currentUser, logout } = useERP();

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['all'] },
    { id: 'inventory', label: 'Stock Management', icon: Package, roles: ['all'] },
    { id: 'invoices', label: 'Invoices & Sales', icon: FileText, roles: ['all'] },
    { id: 'users', label: 'User Management', icon: Users, roles: [UserRole.SUPER_ADMIN, UserRole.HUB_ADMIN] },
    { id: 'finance', label: 'Finance & Payroll', icon: DollarSign, roles: [UserRole.SUPER_ADMIN] },
  ];

  const filteredItems = menuItems.filter(item => 
    item.roles.includes('all') || (currentUser && item.roles.includes(currentUser.role))
  );

  return (
    <>
      {/* Mobile Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-20 md:hidden"
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static ${isOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex items-center justify-between p-4 border-b border-slate-700">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-sun-500 rounded-full flex items-center justify-center text-white font-bold">S</div>
            <span className="text-xl font-bold tracking-tight text-sun-400">Sun Cola ERP</span>
          </div>
          <button onClick={() => setIsOpen(false)} className="md:hidden text-slate-400 hover:text-white">
            <X size={24} />
          </button>
        </div>

        <div className="p-4">
          <div className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">
            {currentUser?.role.replace('_', ' ')}
          </div>
          <div className="text-sm font-medium text-white mb-6">
            {currentUser?.fullName}
          </div>

          <nav className="space-y-1">
            {filteredItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setPage(item.id);
                  setIsOpen(false);
                }}
                className={`w-full flex items-center px-4 py-3 text-sm font-medium rounded-md transition-colors ${
                  currentPage === item.id 
                    ? 'bg-sun-600 text-white shadow-lg' 
                    : 'text-slate-300 hover:bg-slate-800 hover:text-white'
                }`}
              >
                <item.icon className="mr-3 h-5 w-5" />
                {item.label}
              </button>
            ))}
          </nav>
        </div>

        <div className="absolute bottom-0 w-full p-4 border-t border-slate-700">
          <button 
            onClick={logout}
