import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { 
  User, Hub, Product, Stock, Invoice, Customer, Transaction, SalarySlip,
  UserRole
} from '../types';
import { 
  INITIAL_USERS, INITIAL_HUBS, INITIAL_PRODUCTS, INITIAL_STOCKS, 
  INITIAL_CUSTOMERS, HEAD_OFFICE_ID 
} from '../constants';

interface ERPContextType {
  currentUser: User | null;
  login: (username: string) => boolean;
  logout: () => void;
  users: User[];
  addUser: (user: User) => void;
  hubs: Hub[];
  products: Product[];
  stocks: Stock[];
  transferStock: (productId: string, fromHubId: string, toHubId: string, qty: number) => void;
  customers: Customer[];
  addCustomer: (customer: Customer) => void;
  invoices: Invoice[];
  createInvoice: (invoice: Invoice) => void;
  transactions: Transaction[];
  addTransaction: (transaction: Transaction) => void;
  salarySlips: SalarySlip[];
  addSalarySlip: (slip: SalarySlip) => void;
}

const ERPContext = createContext<ERPContextType | undefined>(undefined);

export const ERPProvider = ({ children }: { children?: ReactNode }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // State Initialization (in a real app, this would be DB calls)
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [hubs, setHubs] = useState<Hub[]>(INITIAL_HUBS);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [stocks, setStocks] = useState<Stock[]>(INITIAL_STOCKS);
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_CUSTOMERS);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [salarySlips, setSalarySlips] = useState<SalarySlip[]>([]);

  const login = (username: string) => {
    const user = users.find(u => u.username === username);
    if (user) {
      setCurrentUser(user);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const addUser = (user: User) => setUsers(prev => [...prev, user]);

  const transferStock = (productId: string, fromHubId: string, toHubId: string, qty: number) => {
    setStocks(prev => {
      const newStocks = [...prev];

      // Decrease from source
      const sourceIndex = newStocks.findIndex(s => s.productId === productId && s.hubId === fromHubId);
      if (sourceIndex >= 0 && newStocks[sourceIndex].quantity >= qty) {
        newStocks[sourceIndex] = { ...newStocks[sourceIndex], quantity: newStocks[sourceIndex].quantity - qty };
      } else {
        throw new Error("Insufficient stock");
      }

      // Increase destination
      const destIndex = newStocks.findIndex(s => s.productId === productId && s.hubId === toHubId);
      if (destIndex >= 0) {
        newStocks[destIndex] = { ...newStocks[destIndex], quantity: newStocks[destIndex].quantity + qty };
      } else {
        newStocks.push({ productId, hubId: toHubId, quantity: qty });
      }

      return newStocks;
    });
  };

  const addCustomer = (customer: Customer) => setCustomers(prev => [...prev, customer]);

  const createInvoice = (invoice: Invoice) => {
    // 1. Add Invoice
    setInvoices(prev => [...prev, invoice]);

    // 2. Deduct Stock
    invoice.items.forEach(item => {
        setStocks(prev => {
            const newStocks = [...prev];
            const stockIndex = newStocks.findIndex(s => s.productId === item.productId && s.hubId === invoice.hubId);
            if (stockIndex >= 0) {
                newStocks[stockIndex] = {
                    ...newStocks[stockIndex],
                    quantity: newStocks[stockIndex].quantity - item.quantity
                };
            }
            return newStocks;
        });
    });

    // 3. Add Income Transaction automatically
    addTransaction({
        id: `txn-${Date.now()}`,
        date: new Date().toISOString(),
        type: 'INCOME',
        category: 'SALES',
        amount: invoice.totalAmount,
        description: `Invoice #${invoice.id} payment`,
        hubId: invoice.hubId
    });
  };

  const addTransaction = (transaction: Transaction) => setTransactions(prev => [...prev, transaction]);
  const addSalarySlip = (slip: SalarySlip) => {
      setSalarySlips(prev => [...prev, slip]);
      // Deduct from cash
      addTransaction({
          id: `txn-sal-${slip.id}`,
          date: new Date().toISOString(),
          type: 'EXPENSE',
          category: 'SALARY',
          amount: slip.netSalary,
          description: `Salary for ${slip.employeeName}`,
          hubId: HEAD_OFFICE_ID // Usually salaries paid by HQ
      });
  };

  return (
    <ERPContext.Provider value={{
      currentUser, login, logout,
      users, addUser,
      hubs,
      products,
      stocks, transferStock,
      customers, addCustomer,
      invoices, createInvoice,
      transactions, addTransaction,
      salarySlips, addSalarySlip
    }}>
      {children}
    </ERPContext.Provider>
  );
};

export const useERP = () => {
  const context = useContext(ERPContext);
  if (context === undefined) {
    throw new Error('useERP must be used within an ERPProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { ERPProvider, useERP } from './contexts/ERPContext';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import Invoices from './pages/Invoices';
import Finance from './pages/Finance';
import UsersPage from './pages/Users';
import { Menu } from 'lucide-react';

const LoginPage = () => {
  const { login } = useERP();
  const [username, setUsername] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!login(username)) {
      setError('Invalid username (Try: admin, hub1admin, staff1)');
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-sun-500 to-orange-600 flex items-center justify-center p-4">
      <div className="bg-white p-8 rounded-2xl shadow-2xl max-w-md w-full">
        <div className="text-center mb-8">
            <h1 className="text-4xl font-bold text-sun-600 mb-2">Sun Cola ERP</h1>
            <p className="text-gray-500">Enterprise Resource Planning</p>
        </div>
        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Username</label>
            <input 
              type="text" 
              className="w-full p-3 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500 bg-white text-black"
              placeholder="admin"
              value={username}
              onChange={e => setUsername(e.target.value)}
            />
          </div>
          {error && <p className="text-red-500 text-sm text-center">{error}</p>}
          <button className="w-full bg-slate-900 text-white py-3 rounded-lg font-bold hover:bg-slate-800 transition-all">
            Login to System
          </button>
        </form>
        <div className="mt-6 text-center text-xs text-gray-400">
            <p>Demo Creds: admin, hub1admin, staff1</p>
        </div>
      </div>
    </div>
  );
};

const MainLayout = () => {
  const { currentUser } = useERP();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState('dashboard');

  if (!currentUser) return <LoginPage />;

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'inventory': return <Inventory />;
      case 'invoices': return <Invoices />;
      case 'finance': return <Finance />;
      case 'users': return <UsersPage />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        isOpen={sidebarOpen} 
        setIsOpen={setSidebarOpen} 
        currentPage={currentPage}
        setPage={setCurrentPage}
      />

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {/* Mobile Header */}
        <header className="bg-white border-b border-slate-200 p-4 md:hidden flex justify-between items-center z-10">
          <div className="font-bold text-sun-600">Sun Cola ERP</div>
          <button onClick={() => setSidebarOpen(true)} className="text-slate-600">
            <Menu size={24} />
          </button>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderPage()}
        </main>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <ERPProvider>
      <MainLayout />
    </ERPProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { HEAD_OFFICE_ID } from '../constants';
import { Package, Truck, ArrowRight, RefreshCw } from 'lucide-react';

const Inventory = () => {
  const { products, stocks, hubs, currentUser, transferStock } = useERP();
  const [transferModalOpen, setTransferModalOpen] = useState(false);

  // Transfer State
  const [selectedProduct, setSelectedProduct] = useState('');
  const [targetHub, setTargetHub] = useState('');
  const [transferQty, setTransferQty] = useState(0);

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const getStock = (productId: string, hubId: string) => {
    return stocks.find(s => s.productId === productId && s.hubId === hubId)?.quantity || 0;
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProduct || !targetHub || transferQty <= 0) return;

    try {
        transferStock(selectedProduct, HEAD_OFFICE_ID, targetHub, transferQty);
        setTransferModalOpen(false);
        setTransferQty(0);
        alert("Stock transferred successfully!");
    } catch (err) {
        alert("Transfer failed: Insufficient stock at Head Office.");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Inventory Management</h1>
          <p className="text-slate-500">Real-time stock tracking across all hubs.</p>
        </div>
        {isSuperAdmin && (
          <button 
            onClick={() => setTransferModalOpen(true)}
            className="flex items-center px-4 py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-sm transition-colors"
          >
            <Truck className="mr-2 h-4 w-4" />
            Distribute Stock
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {products.map((product) => (
          <div key={product.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-white rounded-md border border-slate-200">
                  <Package className="text-sun-500 h-6 w-6" />
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">{product.name}</h3>
                  <p className="text-xs text-slate-500">SKU: {product.sku}</p>
                </div>
              </div>
              <div className="text-right">
                <div className="text-sm text-slate-500">Unit Price</div>
                <div className="font-bold text-slate-800">${product.sellingPrice}</div>
              </div>
            </div>

            <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {/* Head Office Stock (Only visible to SA) */}
              {isSuperAdmin && (
                <div className="p-3 bg-indigo-50 rounded-lg border border-indigo-100">
                    <div className="text-xs font-bold text-indigo-800 uppercase mb-1">Head Office (Unified)</div>
                    <div className="text-2xl font-bold text-indigo-900">
                        {getStock(product.id, HEAD_OFFICE_ID).toLocaleString()}
                        <span className="text-xs font-normal text-indigo-600 ml-1">units</span>
                    </div>
                </div>
              )}

              {/* Hub Stocks */}
              {hubs.map(hub => {
                  const qty = getStock(product.id, hub.id);
                  const isMyHub = currentUser?.hubId === hub.id;

                  // Filter visibility: SA sees all, HubAdmin sees own
                  if (!isSuperAdmin && !isMyHub) return null;

                  return (
                    <div key={hub.id} className="p-3 bg-white rounded-lg border border-slate-200">
                         <div className="flex justify-between items-start mb-1">
                            <div className="text-xs font-bold text-slate-600 uppercase">{hub.name}</div>
                            {isMyHub && <div className="px-2 py-0.5 bg-green-100 text-green-700 text-[10px] rounded-full">My Hub</div>}
                         </div>
                        <div className={`text-2xl font-bold ${qty < 100 ? 'text-red-600' : 'text-slate-800'}`}>
                            {qty.toLocaleString()}
                            <span className="text-xs font-normal text-slate-500 ml-1">units</span>
                        </div>
                    </div>
                  );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Transfer Modal */}
      {transferModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl max-w-md w-full p-6 shadow-2xl animate-fade-in">
            <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
                <RefreshCw className="mr-2 text-sun-600" />
                Distribute Stock
            </h2>
            <form onSubmit={handleTransfer} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Product</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none bg-white text-black"
                        value={selectedProduct}
                        onChange={e => setSelectedProduct(e.target.value)}
                        required
                    >
                        <option value="">Select Product</option>
                        {products.map(p => (
                            <option key={p.id} value={p.id}>{p.name} (HQ: {getStock(p.id, HEAD_OFFICE_ID)})</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Destination Hub</label>
                    <select 
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none bg-white text-black"
                        value={targetHub}
                        onChange={e => setTargetHub(e.target.value)}
                        required
                    >
                        <option value="">Select Hub</option>
                        {hubs.map(h => (
                            <option key={h.id} value={h.id}>{h.name}</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Quantity</label>
                    <input 
                        type="number" 
                        min="1"
                        className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sun-500 focus:border-sun-500 outline-none bg-white text-black"
                        value={transferQty}
                        onChange={e => setTransferQty(parseInt(e.target.value))}
                        required
                    />
                </div>

                <div className="flex space-x-3 mt-6">
                    <button 
                        type="button"
                        onClick={() => setTransferModalOpen(false)}
                        className="flex-1 py-2 px-4 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit"
                        className="flex-1 py-2 px-4 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md"
                    >
                        Transfer
                    </button>
                </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { InvoiceTemplate } from '../services/invoiceGenerator';
import { UserRole, Invoice, InvoiceItem } from '../types';
import { Plus, Trash2, Printer, Share2, Search, FilePlus } from 'lucide-react';

const Invoices = () => {
  const { 
    currentUser, products, customers, invoices, 
    createInvoice, addCustomer, stocks 
  } = useERP();

  const [view, setView] = useState<'LIST' | 'CREATE'>('LIST');
  const [searchTerm, setSearchTerm] = useState('');

  // Creation State
  const [newCustType, setNewCustType] = useState<'EXISTING' | 'NEW'>('EXISTING');
  const [selectedCustId, setSelectedCustId] = useState('');
  const [guestDetails, setGuestDetails] = useState({ name: '', phone: '', address: '' });
  const [cart, setCart] = useState<InvoiceItem[]>([]);

  // Filter invoices for current user's hub (unless SA)
  const myHubId = currentUser?.hubId;
  const filteredInvoices = invoices.filter(inv => {
    const matchesSearch = inv.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || inv.id.includes(searchTerm);
    if (currentUser?.role === UserRole.SUPER_ADMIN) return matchesSearch;
    return inv.hubId === myHubId && matchesSearch;
  });

  const getStock = (productId: string) => {
    const hub = currentUser?.hubId;
    if (!hub) return 0;
    return stocks.find(s => s.productId === productId && s.hubId === hub)?.quantity || 0;
  };

  const addToCart = (productId: string) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    const currentQtyInCart = cart.find(c => c.productId === productId)?.quantity || 0;
    const available = getStock(productId);

    if (currentQtyInCart + 1 > available) {
        alert("Insufficient stock in your hub!");
        return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.productId === productId);
      if (existing) {
        return prev.map(item => item.productId === productId ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { productId, quantity: 1, priceAtSale: product.sellingPrice }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.productId !== productId));
  };

  const handleCreateInvoice = () => {
    if (cart.length === 0) return;

    let custId = selectedCustId;
    let custName = '';

    if (newCustType === 'NEW') {
        custId = `c-${Date.now()}`;
        custName = guestDetails.name;
        addCustomer({
            id: custId,
            name: guestDetails.name,
            phone: guestDetails.phone,
            address: guestDetails.address,
            type: 'GUEST' // Or REGISTERED if you want full reg
        });
    } else {
        const c = customers.find(c => c.id === selectedCustId);
        if (!c) return alert("Select a customer");
        custName = c.name;
    }

    const total = cart.reduce((acc, item) => acc + (item.quantity * item.priceAtSale), 0);

    const newInvoice: Invoice = {
        id: `INV-${Date.now().toString().slice(-6)}`,
        date: new Date().toISOString(),
        customerId: custId,
        customerName: custName,
        hubId: currentUser?.hubId || 'HEAD_OFFICE',
        items: cart,
        totalAmount: total,
        status: 'PAID', // Assuming instant cash payment for this ERP
        createdBy: currentUser?.id || 'unknown'
    };

    createInvoice(newInvoice);
    setView('LIST');
    setCart([]);
    setGuestDetails({ name: '', phone: '', address: '' });
  };

  const handlePrint = (invId: string) => {
      // Logic to trigger browser print
      const printContent = document.getElementById(`invoice-${invId}`);
      if (printContent) {
          window.print();
      } else {
          alert("Rendering invoice for print... please wait a split second and try again (in real app this opens a PDF url)");
      }
  };

  const handleWhatsApp = (inv: Invoice) => {
      const customer = customers.find(c => c.id === inv.customerId);
      const phone = customer?.phone || '0000000000';
      const message = `Hello ${inv.customerName}, here is your invoice #${inv.id} from Sun Cola for $${inv.totalAmount}. Thank you!`;
      const url = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;
      window.open(url, '_blank');
  };

  return (
    <div className="space-y-6">
       {/* Invoice Template Rendering Area (Hidden until print) */}
       <div>
         {invoices.map(inv => (
             <InvoiceTemplate 
                key={inv.id} 
                invoice={inv} 
                products={products} 
                customer={customers.find(c => c.id === inv.customerId)} 
             />
         ))}
       </div>

      <div className="flex justify-between items-center no-print">
        <h1 className="text-2xl font-bold text-slate-800">{view === 'LIST' ? 'Invoices' : 'New Invoice'}</h1>
        {view === 'LIST' && currentUser?.role !== UserRole.SUPER_ADMIN && (
          <button 
            onClick={() => setView('CREATE')}
            className="flex items-center px-4 py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md"
          >
            <Plus className="mr-2 h-4 w-4" />
            Create Invoice
          </button>
        )}
        {view === 'CREATE' && (
          <button onClick={() => setView('LIST')} className="text-slate-500 hover:text-slate-800">Cancel</button>
        )}
      </div>

      {view === 'LIST' ? (
        <div className="space-y-4 no-print">
            <div className="relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-slate-400" />
                <input 
                    type="text" 
                    placeholder="Search invoices..." 
                    className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-sun-500 outline-none bg-white text-black"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-slate-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Invoice ID</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Customer</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Date</th>
                                <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">Amount</th>
                                <th className="px-6 py-3 text-center text-xs font-bold text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-slate-200">
                            {filteredInvoices.map(inv => (
                                <tr key={inv.id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">#{inv.id}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{inv.customerName}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{new Date(inv.date).toLocaleDateString()}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-right font-bold text-slate-700">${inv.totalAmount.toFixed(2)}</td>
                                    <td className="px-6 py-4 whitespace-nowrap text-center text-sm font-medium space-x-2">
                                        <button onClick={() => handlePrint(inv.id)} className="text-slate-600 hover:text-sun-600">
                                            <Printer size={18} />
                                        </button>
                                        {(currentUser?.role === UserRole.SUPER_ADMIN) && (
                                            <button onClick={() => handleWhatsApp(inv)} className="text-green-600 hover:text-green-800">
                                                <Share2 size={18} />
                                            </button>
                                        )}
                                    </td>
                                </tr>
                            ))}
                            {filteredInvoices.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-slate-400">No invoices found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
            {/* Left: Product Selection */}
            <div className="lg:col-span-2 space-y-6">
                <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="font-bold text-slate-800 mb-4">Select Products</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                        {products.map(p => {
                            const stock = getStock(p.id);
                            return (
                                <button 
                                    key={p.id}
                                    onClick={() => addToCart(p.id)}
                                    disabled={stock === 0}
                                    className={`p-4 rounded-lg border text-left transition-all ${
                                        stock > 0 
                                        ? 'border-slate-200 hover:border-sun-500 hover:bg-sun-50' 
                                        : 'border-slate-100 bg-slate-50 opacity-50 cursor-not-allowed'
                                    }`}
                                >
                                    <div className="font-bold text-slate-800">{p.name}</div>
                                    <div className="text-sm text-slate-500">${p.sellingPrice}</div>
                                    <div className={`text-xs mt-2 ${stock < 10 ? 'text-red-500' : 'text-green-600'}`}>
                                        Stock: {stock}
                                    </div>
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                     <h3 className="font-bold text-slate-800 mb-4">Customer Details</h3>
                     <div className="flex space-x-4 mb-4">
                         <button 
                            className={`flex-1 py-2 rounded-lg text-sm font-medium ${newCustType === 'EXISTING' ? 'bg-sun-100 text-sun-800' : 'bg-slate-100 text-slate-600'}`}
                            onClick={() => setNewCustType('EXISTING')}
                         >
                             Existing Customer
                         </button>
                         <button 
                            className={`flex-1 py-2 rounded-lg text-sm font-medium ${newCustType === 'NEW' ? 'bg-sun-100 text-sun-800' : 'bg-slate-100 text-slate-600'}`}
                            onClick={() => setNewCustType('NEW')}
                         >
                             New / Guest
                         </button>
                     </div>

                     {newCustType === 'EXISTING' ? (
                         <select 
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none bg-white text-black"
                            value={selectedCustId}
                            onChange={(e) => setSelectedCustId(e.target.value)}
                         >
                             <option value="">Select Customer</option>
                             {customers.map(c => (
                                 <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                             ))}
                         </select>
                     ) : (
                         <div className="space-y-3">
                             <input 
                                type="text" placeholder="Full Name" className="w-full p-2 border border-slate-300 rounded-lg bg-white text-black"
                                value={guestDetails.name} onChange={e => setGuestDetails({...guestDetails, name: e.target.value})}
                             />
                             <input 
                                type="text" placeholder="Phone Number" className="w-full p-2 border border-slate-300 rounded-lg bg-white text-black"
                                value={guestDetails.phone} onChange={e => setGuestDetails({...guestDetails, phone: e.target.value})}
                             />
                             <input 
                                type="text" placeholder="Address (Optional)" className="w-full p-2 border border-slate-300 rounded-lg bg-white text-black"
                                value={guestDetails.address} onChange={e => setGuestDetails({...guestDetails, address: e.target.value})}
                             />
                         </div>
                     )}
                </div>
            </div>

            {/* Right: Cart Summary */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
                <h3 className="font-bold text-lg text-slate-800 mb-4">Current Invoice</h3>
                <div className="space-y-4 mb-6">
                    {cart.map(item => {
                        const p = products.find(prod => prod.id === item.productId);
                        return (
                            <div key={item.productId} className="flex justify-between items-center text-sm">
                                <div>
                                    <div className="font-medium text-slate-800">{p?.name}</div>
                                    <div className="text-slate-500">{item.quantity} x ${item.priceAtSale}</div>
                                </div>
                                <div className="flex items-center space-x-3">
                                    <span className="font-bold text-slate-800">${(item.quantity * item.priceAtSale).toFixed(2)}</span>
                                    <button onClick={() => removeFromCart(item.productId)} className="text-red-400 hover:text-red-600">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                    {cart.length === 0 && (
                        <div className="text-center text-slate-400 py-4">Cart is empty</div>
                    )}
                </div>

                <div className="border-t border-slate-200 pt-4 mb-6">
                    <div className="flex justify-between items-center text-xl font-bold text-slate-800">
                        <span>Total</span>
                        <span>${cart.reduce((acc, item) => acc + (item.quantity * item.priceAtSale), 0).toFixed(2)}</span>
                    </div>
                </div>

                <button 
                    onClick={handleCreateInvoice}
                    disabled={cart.length === 0}
                    className="w-full py-3 bg-sun-600 text-white font-bold rounded-lg hover:bg-sun-700 shadow-lg disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center"
                >
                    <FilePlus className="mr-2 h-5 w-5" />
                    Generate Invoice
                </button>
            </div>
        </div>
      )}
    </div>
  );
};

export default Invoices;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole } from '../types';
import { DollarSign, Wallet, FileText, PieChart as PieChartIcon } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

const Finance = () => {
  const { currentUser, transactions, addSalarySlip, salarySlips } = useERP();
  const [activeTab, setActiveTab] = useState<'PNL' | 'SALARY'>('PNL');

  // Salary Form
  const [empName, setEmpName] = useState('');
  const [salary, setSalary] = useState(0);

  if (currentUser?.role !== UserRole.SUPER_ADMIN) {
      return <div className="text-red-500">Access Denied</div>;
  }

  // Financial Calcs
  const totalIncome = transactions.filter(t => t.type === 'INCOME').reduce((acc, c) => acc + c.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'EXPENSE').reduce((acc, c) => acc + c.amount, 0);
  const netProfit = totalIncome - totalExpense;

  const dataPnl = [
      { name: 'Income', value: totalIncome, color: '#10b981' },
      { name: 'Expense', value: totalExpense, color: '#ef4444' }
  ];

  const handleCreateSalary = (e: React.FormEvent) => {
      e.preventDefault();
      if (!empName || salary <= 0) return;

      addSalarySlip({
          id: Date.now().toString(),
          employeeName: empName,
          role: 'Staff',
          month: new Date().toLocaleString('default', { month: 'long' }),
          basicSalary: salary,
          bonus: 0,
          deductions: 0,
          netSalary: salary,
          dateGenerated: new Date().toISOString()
      });
      setEmpName('');
      setSalary(0);
  };

  return (
    <div className="space-y-6">
      <div className="flex space-x-4 border-b border-slate-200 pb-4">
        <button 
            onClick={() => setActiveTab('PNL')}
            className={`flex items-center px-4 py-2 rounded-lg font-medium transition-colors ${activeTab === 'PNL' ? 'bg-sun-100 text-sun-700' : 'text-slate-500 hover:bg-slate-50'}`}
        >
            <PieChartIcon className="mr-2 h-5 w-5" />
            Profit & Loss
        </button>
        <button 
            onClick={() => setActiveTab('SALARY')}
            className={`flex items-center px-4 py-2 rounded-lg font-medium transition-colors ${activeTab === 'SALARY' ? 'bg-sun-100 text-sun-700' : 'text-slate-500 hover:bg-slate-50'}`}
        >
            <Wallet className="mr-2 h-5 w-5" />
            Cash & Payroll
        </button>
      </div>

      {activeTab === 'PNL' ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                <h2 className="text-lg font-bold text-slate-800 mb-6">Financial Overview</h2>
                <div className="space-y-4">
                    <div className="flex justify-between items-center p-4 bg-green-50 rounded-lg border border-green-100">
                        <span className="text-green-800 font-medium">Total Income</span>
                        <span className="text-xl font-bold text-green-700">+${totalIncome.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center p-4 bg-red-50 rounded-lg border border-red-100">
                        <span className="text-red-800 font-medium">Total Expenses</span>
                        <span className="text-xl font-bold text-red-700">-${totalExpense.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center p-4 bg-slate-50 rounded-lg border border-slate-200 mt-4">
                        <span className="text-slate-800 font-bold">Net Profit</span>
                        <span className={`text-2xl font-bold ${netProfit >= 0 ? 'text-blue-600' : 'text-red-600'}`}>
                            ${netProfit.toLocaleString()}
                        </span>
                    </div>
                </div>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col items-center justify-center">
                 <h2 className="text-lg font-bold text-slate-800 mb-4">Ratio Analysis</h2>
                 <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie 
                                data={dataPnl} 
                                innerRadius={60} 
                                outerRadius={80} 
                                paddingAngle={5} 
                                dataKey="value"
                            >
                                {dataPnl.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
                            </Pie>
                            <Tooltip />
                        </PieChart>
                    </ResponsiveContainer>
                 </div>
                 <div className="flex space-x-6 mt-4">
                     {dataPnl.map((item, idx) => (
                         <div key={idx} className="flex items-center text-sm">
                             <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: item.color }}></div>
                             <span className="text-slate-600">{item.name}</span>
                         </div>
                     ))}
                 </div>
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
                <h2 className="text-lg font-bold text-slate-800 mb-4">Generate Salary Slip</h2>
                <form onSubmit={handleCreateSalary} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-600 mb-1">Employee Name</label>
                        <input 
                            type="text" required
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500 bg-white text-black"
                            value={empName} onChange={e => setEmpName(e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-600 mb-1">Net Pay Amount ($)</label>
                        <input 
                            type="number" required min="1"
                            className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-sun-500 bg-white text-black"
                            value={salary} onChange={e => setSalary(parseFloat(e.target.value))}
                        />
                    </div>
                    <button className="w-full py-2 bg-sun-600 text-white rounded-lg hover:bg-sun-700 shadow-md">
                        Process Payment
                    </button>
                </form>
            </div>

            <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 border-b border-slate-200 bg-slate-50">
                    <h2 className="font-bold text-slate-700">Recent Salary Disbursements</h2>
                </div>
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-white">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Employee</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Month</th>
                                <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">Net Pay</th>
                                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Date</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200">
                            {salarySlips.map(slip => (
                                <tr key={slip.id} className="hover:bg-slate-50">
                                    <td className="px-6 py-4 text-sm font-medium text-slate-900">{slip.employeeName}</td>
                                    <td className="px-6 py-4 text-sm text-slate-500">{slip.month}</td>
                                    <td className="px-6 py-4 text-sm text-right font-bold text-slate-700">${slip.netSalary}</td>
                                    <td className="px-6 py-4 text-sm text-slate-500">{new Date(slip.dateGenerated).toLocaleDateString()}</td>
                                </tr>
                            ))}
                            {salarySlips.length === 0 && (
                                <tr><td colSpan={4} className="text-center py-6 text-slate-400">No records found</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Finance;

import React, { useState } from 'react';
import { useERP } from '../contexts/ERPContext';
import { UserRole, User } from '../types';
import { INITIAL_HUBS } from '../constants';
import { Users as UserIcon, Shield, MapPin, Plus } from 'lucide-react';

const UsersPage = () => {
  const { users, addUser, hubs, currentUser } = useERP();
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [newUser, setNewUser] = useState<Partial<User>>({
      username: '', fullName: '', role: UserRole.STAFF, hubId: ''
  });

  const isSuperAdmin = currentUser?.role === UserRole.SUPER_ADMIN;

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newUser.username || !newUser.fullName) return;

      addUser({
          id: `u-${Date.now()}`,
          username: newUser.username,
          fullName: newUser.fullName,
          role: newUser.role as UserRole,
          hubId: newUser.role === UserRole.SUPER_ADMIN ? undefined : (newUser.hubId || currentUser?.hubId),
          permissions: [],
          phone: ''
      });
      setShowForm(false);
      setNewUser({ username: '', fullName: '', role: UserRole.STAFF, hubId: '' });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">User Management</h1>
           <p className="text-slate-500">Manage system access and roles.</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-colors"
        >
          <Plus className="mr-2 h-4 w-4" />
          Add User
        </button>
      </div>

      {showForm && (
          <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200 animate-fade-in">
              <h3 className="text-lg font-bold mb-4">Create New User</h3>
              <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input 
                    placeholder="Username" required
                    className="p-2 border border-slate-300 rounded-lg bg-white text-black"
                    value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})}
                  />
                  <input 
                    placeholder="Full Name" required
                    className="p-2 border border-slate-300 rounded-lg bg-white text-black"
                    value={newUser.fullName} onChange={e => setNewUser({...newUser, fullName: e.target.value})}
                  />
                  <select 
                    className="p-2 border border-slate-300 rounded-lg bg-white text-black"
                    value={newUser.role} 
                    onChange={e => setNewUser({...newUser, role: e.target.value as UserRole})}
                  >
                      <option value={UserRole.STAFF}>Staff</option>
                      {isSuperAdmin && <option value={UserRole.HUB_ADMIN}>Hub Admin</option>}
                      {isSuperAdmin && <option value={UserRole.SUPER_ADMIN}>Super Admin</option>}
                  </select>

                  {/* Hub Selection only if SA creating Hub Admin or Staff */}
                  {isSuperAdmin && newUser.role !== UserRole.SUPER_ADMIN && (
                      <select 
                        className="p-2 border border-slate-300 rounded-lg bg-white text-black"
                        value={newUser.hubId} 
                        onChange={e => setNewUser({...newUser, hubId: e.target.value})}
                        required
                      >
                          <option value="">Select Hub</option>
                          {hubs.map(h => <option key={h.id} value={h.id}>{h.name}</option>)}
                      </select>
                  )}

                  <div className="md:col-span-2 flex justify-end mt-2">
                      <button type="submit" className="px-6 py-2 bg-sun-600 text-white rounded-lg font-medium">Create User</button>
                  </div>
              </form>
          </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(user => (
              <div key={user.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col relative overflow-hidden group">
                  <div className={`absolute top-0 left-0 w-1 h-full ${
                      user.role === UserRole.SUPER_ADMIN ? 'bg-purple-500' :
                      user.role === UserRole.HUB_ADMIN ? 'bg-blue-500' : 'bg-green-500'
                  }`} />

                  <div className="flex items-start justify-between mb-4 pl-3">
                      <div className="flex items-center space-x-3">
                          <div className="bg-slate-100 p-2 rounded-full">
                              <UserIcon size={20} className="text-slate-600" />
                          </div>
                          <div>
                              <h3 className="font-bold text-slate-800">{user.fullName}</h3>
                              <p className="text-sm text-slate-500">@{user.username}</p>
                          </div>
                      </div>
                      <span className="text-xs font-bold uppercase px-2 py-1 bg-slate-100 text-slate-600 rounded">
                          {user.role.replace('_', ' ')}
                      </span>
                  </div>

                  <div className="pl-3 mt-auto space-y-2">
                      <div className="flex items-center text-sm text-slate-600">
                          <Shield size={14} className="mr-2 text-slate-400" />
                          <span>{user.role === UserRole.SUPER_ADMIN ? 'Full Access' : 'Restricted Access'}</span>
                      </div>
                      {user.hubId && (
                          <div className="flex items-center text-sm text-slate-600">
                              <MapPin size={14} className="mr-2 text-slate-400" />
                              <span>{hubs.find(h => h.id === user.hubId)?.name || 'Unknown Hub'}</span>
                          </div>
                      )}
                  </div>
              </div>
          ))}
      </div>
    </div>
  );
};

export default UsersPage;
